// Embedded nautilus animation atlas: a realistic 12-frame, 128x128 sprite sheet
// (1536x128 PNG) baked in as a base64 data URL. This is the one deliberate
// exception to the "procedural sprites, not files" convention (see CLAUDE.md) —
// embedding keeps the single-binary build with no asset pipeline. Source PNG
// lives at art/nautilus-atlas-128.png. makeNautilusSprite() in cephalopod.ts
// smooth-downscales this to ~fish size at load.
export const NAUTILUS_ATLAS = "data:image/png;base64,";
export const NAUTILUS_FRAMES = 12;
